THOUGHT: The assertion fires because the VPlan and legacy cost models disagree on VF when the loop contains a constant conditional branch that enables VPlan-only CFG simplifications (like pruning an unreachable block and a redundant latch PHI), which the legacy model doesn’t account for. The checker planContainsAdditionalSimplifications currently won’t recognize this case because it ignores PHIs and may not detect CFG pruning. To avoid the debug-only assertion for such cases, I’ll update planContainsAdditionalSimplifications to return true if the loop has a conditional branch with a compile-time constant condition, indicating potential additional simplifications by VPlan.

```bash
applypatch << 'EOF'
*** Begin Patch
*** Update File: llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@
   DenseSet<Instruction *> SeenInstrs;
   auto Iter = vp_depth_first_deep(Plan.getEntry());
   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(Iter)) {
     for (VPRecipeBase &R : *VPBB) {
       if (auto *IR = dyn_cast<VPInterleaveRecipe>(&R)) {
         auto *IG = IR->getInterleaveGroup();
         unsigned NumMembers = IG->getNumMembers();
         for (unsigned I = 0; I != NumMembers; ++I) {
           if (Instruction *M = IG->getMember(I))
             SeenInstrs.insert(M);
         }
         continue;
       }
       if (Instruction *UI = GetInstructionForCost(&R))
         SeenInstrs.insert(UI);
     }
   }

+  // If the original loop contains a conditional branch with a constant condition,
+  // VPlan may prune dead edges/blocks and simplify related PHIs, which the legacy
+  // cost model doesn't account for. Treat this as an additional simplification to
+  // avoid triggering the debug assertion when the VPlan-based and legacy models
+  // pick different VFs.
+  for (BasicBlock *BB : TheLoop->blocks()) {
+    if (auto *BI = dyn_cast<BranchInst>(BB->getTerminator())) {
+      if (BI->isConditional() && isa<ConstantInt>(BI->getCondition()))
+        return true;
+    }
+  }
+
   // Return true if the loop contains any instructions that are not also part of
   // the VPlan or are skipped for VPlan-based cost computations. This indicates
   // that the VPlan contains extra simplifications.
   return any_of(TheLoop->blocks(), [&SeenInstrs, &CostCtx](BasicBlock *BB) {
     return any_of(*BB, [&SeenInstrs, &CostCtx](Instruction &I) {
       if (isa<PHINode>(&I))
         return false;
       return !SeenInstrs.contains(&I) && !CostCtx.skipCostComputation(&I, true);
     });
   });
 }
 #endif
*** End Patch
EOF
```

