from pathlib import Path

p = Path("llvm/lib/Transforms/Vectorize/LoopVectorize.cpp")
s = p.read_text()

needle = "  // Return true if the loop contains any instructions that are not also part of"
insertion = """  // If the original loop contains a conditional branch with a constant condition,
  // VPlan may prune dead edges/blocks and simplify related PHIs, which the legacy
  // cost model doesn't account for. Treat this as an additional simplification to
  // avoid triggering the debug assertion when the VPlan-based and legacy models
  // pick different VFs.
  for (BasicBlock *BB : TheLoop->blocks()) {
